import pika
import subprocess
import logging

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def callback(ch, method, properties, body):
    command = body.decode('utf-8')
    logging.info(f"Received command: {command}")

    try:
        # Execute the command
        # For security, consider carefully what commands can be executed.
        # This example directly runs the command from the message body.
        # In a real system, you might want to whitelist commands or
        # use a more robust task execution framework.
        result = subprocess.run(
            command,
            shell=True,
            check=True,  # Raise CalledProcessError if the command returns a non-zero exit code
            capture_output=True,
            text=True
        )
        logging.info(f"Command '{command}' executed successfully.")
        logging.info(f"STDOUT:\n{result.stdout}")
        if result.stderr:
            logging.warning(f"STDERR:\n{result.stderr}")
        ch.basic_ack(delivery_tag=method.delivery_tag)
    except subprocess.CalledProcessError as e:
        logging.error(f"Command '{command}' failed with exit code {e.returncode}.")
        logging.error(f"STDOUT:\n{e.stdout}")
        logging.error(f"STDERR:\n{e.stderr}")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False) # Don't re-queue failed messages by default
    except Exception as e:
        logging.critical(f"An unexpected error occurred while processing command '{command}': {e}")
        ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False) # Don't re-queue messages that cause general exceptions

def main():
    RABBITMQ_HOST = 'localhost' # Replace with your RabbitMQ host
    QUEUE_NAME = 'batch_jobs'

    try:
        connection = pika.BlockingConnection(pika.ConnectionParameters(host=RABBITMQ_HOST))
        channel = connection.channel()

        # Declare the queue. It's idempotent, so it can be called multiple times.
        # Using durable=True to ensure messages survive a RabbitMQ restart.
        channel.queue_declare(queue=QUEUE_NAME, durable=True)
        logging.info(f'Waiting for messages in queue: {QUEUE_NAME}. To exit press CTRL+C')

        # Only deliver one message at a time to this consumer (fair dispatch)
        channel.basic_qos(prefetch_count=1)
        channel.basic_consume(queue=QUEUE_NAME, on_message_callback=callback)

        channel.start_consuming()

    except pika.exceptions.AMQPConnectionError as e:
        logging.critical(f"Failed to connect to RabbitMQ: {e}")
    except KeyboardInterrupt:
        logging.info("Consumer stopped by user.")
    except Exception as e:
        logging.critical(f"An unhandled error occurred in the main loop: {e}")
    finally:
        if 'connection' in locals() and connection.is_open:
            connection.close()
            logging.info("RabbitMQ connection closed.")

if __name__ == '__main__':
    main()